local a=require"ecnet2.class"local b=require"ccryptolib.aead"local c=require"ccryptolib.chacha20"local d=a"ecnet2.CipherState"function d:initialise(e)self.k=e;self.n=0 end;function d:hasKey()return self.k~=nil end;function d:setNonce(f)self.n=f end;function d:rekey()self.k=c.crypt(self.k,("<I12"):pack(2^64-1),("\0"):rep(32),8)end;function d:descriptor()local g=c.crypt(self.k,("<I12"):pack(2^64-1),("\0"):rep(64),8)return g:sub(33)end;function d:encryptWithAd(h,i)if self:hasKey()then local f=("<I12"):pack(self.n)local j,k=b.encrypt(self.k,f,i,h,8)self.n=self.n+1;return j..k else return i end end;function d:decryptWithAd(h,l)if self:hasKey()then if#l<16 then return end;local j,k=l:sub(1,-17),l:sub(-16)local f=("<I12"):pack(self.n)local i=b.decrypt(self.k,f,k,j,h,8)self.n=self.n+1;return i else return l end end;return d
